INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'cf4258a6-d427-46f5-9ded-32bfa7ab2755',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC — Protobuf Schemas, Streaming Types, and When to Ditch REST$escape$,
  $escape$gRPC uses Protocol Buffers as its IDL and wire format — not JSON. Every service contract lives in a `.proto` file, compiled via `protoc` into type-safe stubs. Fields are numbered (not named) on the wire, making schema evolution safe: adding a new field with a new number is backward-compatible; never reuse or remove numbers.

Four streaming modes exist in gRPC: unary (one request, one response — closest to REST), server streaming (one request, many responses — ideal for live feeds or log tailing), client streaming (many requests, one response — good for chunked uploads), and bidirectional streaming (full-duplex — chat, real-time telemetry).

Choose gRPC over REST when: (1) you control both client and server, (2) you need strict contracts enforced at compile time, (3) latency matters — HTTP/2 multiplexing eliminates head-of-line blocking, (4) you need streaming semantics without WebSocket complexity. Avoid gRPC when browser clients must call your API directly without a proxy like gRPC-Web or Connect.$escape$,
  $escape$// user.proto
syntax = "proto3";

service UserService {
  rpc GetUser (GetUserRequest) returns (User);                          // unary
  rpc WatchUserActivity (WatchRequest) returns (stream ActivityEvent); // server stream
  rpc UploadAvatar (stream Chunk) returns (UploadResult);             // client stream
  rpc Chat (stream ChatMessage) returns (stream ChatMessage);         // bidi stream
}

message GetUserRequest { string user_id = 1; }
message User { string user_id = 1; string name = 2; int64 created_at = 3; }
message ActivityEvent { string event_type = 1; int64 timestamp = 2; }
message Chunk { bytes data = 1; }
message UploadResult { string url = 1; }
message ChatMessage { string sender_id = 1; string text = 2; }$escape$,
