INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '178c5dc3-6d56-4bad-bb26-63c561a2da20',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Pagination — Cursor vs Offset, Total Counts, and Infinite Scroll$escape$,
  $escape$gRPC has no built-in pagination — you define it in your Protobuf schema. The two dominant patterns are offset (`page_token` as an integer) and cursor-based (`page_token` as an opaque string). Prefer cursors: they're stable under concurrent writes and avoid the 'drifting rows' problem that plagues offset pagination when items are inserted mid-fetch.

Define your paginated RPCs using Google's AIP-158 standard: return a `next_page_token` string and accept a `page_token` + `page_size` in the request. If `next_page_token` is empty, the client has reached the last page — no total count needed. For infinite scroll, clients loop: fetch → render → fetch next token → repeat until token is empty.

Avoid returning `total_count` by default. It requires a full table scan (expensive) and is meaningless under cursor pagination since the result set shifts. If you must expose it, gate it behind a `bool request_total` field and compute it only when explicitly requested. For gRPC streaming use cases, prefer server-streaming RPCs over repeated unary calls — stream pages directly and close the stream on exhaustion.$escape$,
  $escape$// pagination.proto
message ListBytesRequest {
  string page_token = 1;  // opaque cursor, empty = first page
  int32  page_size  = 2;  // max 100, default 20
  bool   request_total = 3; // opt-in: triggers COUNT(*)
}

message ListBytesResponse {
  repeated Byte bytes          = 1;
  string        next_page_token = 2; // empty = last page
  optional int64 total_count   = 3; // only set if request_total=true
}

service ByteService {
  rpc ListBytes(ListBytesRequest) returns (ListBytesResponse);
}$escape$,
