INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '19ee5b45-9986-4e36-9f8c-577c4b40501b',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Rate Limiting — Per-Endpoint, Per-User, and Choosing Between Token Bucket and Sliding Window$escape$,
  $escape$gRPC rate limiting belongs in interceptors — `grpc.UnaryInterceptor` for unary RPCs, `grpc.StreamInterceptor` for server/client/bidi streams. The canonical per-endpoint key is `info.FullMethod`, which yields the fully-qualified path (`/package.Service/Method`). Per-user identity comes from incoming metadata via `metadata.FromIncomingContext(ctx)` — typically a `x-user-id` value stamped by your auth interceptor earlier in the chain.

Token bucket (`golang.org/x/time/rate`) fits bursty gRPC traffic well: it absorbs short spikes while enforcing a steady refill rate. Store one `rate.Limiter` per `userID + ":" + method` in a `sync.Map` (~200 bytes each). Sliding window counters (Redis `ZADD` + `ZREMRANGEBYSCORE`) are more precise under sustained load but cost a network round-trip per RPC — acceptable for expensive write methods, problematic for high-frequency reads like `ListFeed`.

When a limit fires, return `codes.ResourceExhausted`. gRPC clients using the default backoff policy will retry with exponential delay. Attach a `retry-after` trailer via `grpc.SetTrailer(ctx, metadata.Pairs("retry-after", "2s"))` so clients can back off precisely instead of guessing.$escape$,
  $escape$var limiters sync.Map

func RateLimitInterceptor(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
	md, _ := metadata.FromIncomingContext(ctx)
	uids := md.Get("x-user-id")
	if len(uids) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing user id")
	}
	key := uids[0] + ":" + info.FullMethod
	v, _ := limiters.LoadOrStore(key, rate.NewLimiter(rate.Every(time.Second), 10))
	if !v.(*rate.Limiter).Allow() {
		grpc.SetTrailer(ctx, metadata.Pairs("retry-after", "1s"))
		return nil, status.Error(codes.ResourceExhausted, "rate limit exceeded")
	}
	return handler(ctx, req)
}$escape$,
