INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '547c14eb-0af5-4501-a516-59ad7fc619de',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Error Handling — Consistent Problem+JSON Across HTTP Transcoding$escape$,
  $escape$gRPC's native error model (`google.rpc.Status`) carries a `Code`, `message`, and typed `details` — rich enough internally, but when gRPC-Gateway transcodes to REST, the default error envelope looks nothing like Problem+JSON (RFC 7807). Clients expecting `application/problem+json` get something unrecognizable.

Fix it by registering a custom `runtime.WithErrorHandler` on your `ServeMux`. Inside, call `status.Convert(err)` to extract the gRPC `Status`, then use `runtime.HTTPStatusFromCode(s.Code())` for the HTTP status and map `s.Message()` to `detail`. For richer context, iterate `s.Details()` — each entry is a proto Any that may hold `google.rpc.ErrorInfo`, `google.rpc.BadRequest.FieldViolation`, or custom types — and append them under an `extensions` key.

On the gRPC side, always return errors via `status.Errorf(codes.InvalidArgument, "field X: %v", err)` rather than bare `errors.New`. This keeps the code/message contract intact through transcoding, so your Problem+JSON renderer always has well-typed, consistently structured input regardless of whether the caller hit the gRPC port or the HTTP gateway.$escape$,
  $escape$func problemJSONErrorHandler(ctx context.Context, mux *runtime.ServeMux,
	m runtime.Marshaler, w http.ResponseWriter, r *http.Request, err error) {

	s := status.Convert(err)
	w.Header().Set("Content-Type", "application/problem+json")
	w.WriteHeader(runtime.HTTPStatusFromCode(s.Code()))

	json.NewEncoder(w).Encode(map[string]any{
		"type":   fmt.Sprintf("https://api.example.com/errors/%s", s.Code()),
		"title":  s.Code().String(),
		"status": runtime.HTTPStatusFromCode(s.Code()),
		"detail": s.Message(),
	})
}

// Wire it up
mux := runtime.NewServeMux(
	runtime.WithErrorHandler(problemJSONErrorHandler),
)$escape$,
  $escape$go$escape$,
