INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '5372763e-126b-4470-8fbf-9b1cc303b196',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Idempotency — Method Options, Retry Safety, and Idempotency Keys$escape$,
  $escape$gRPC transmits every call as an HTTP/2 POST, so the transport enforces no safe/idempotent semantics — you must declare them explicitly. Protobuf's `IdempotencyLevel` method option does this: `NO_SIDE_EFFECTS` (read-only, equivalent to GET) and `IDEMPOTENT` (repeatable writes, equivalent to PUT) both unlock automatic client retries under gRPC's built-in retry policy. The default, `IDEMPOTENCY_UNKNOWN`, disables automatic retries entirely.

For non-idempotent mutations like `CreateOrder`, `IDEMPOTENCY_UNKNOWN` is semantically correct — but you still need network-level safety. The pattern: require an `idempotency-key` metadata header from the caller, store `(key → serialized response)` in Redis with a TTL, and replay the cached response on duplicates. Extract the key server-side via `metadata.FromIncomingContext(ctx)` and reject absent keys with `codes.InvalidArgument`.

Wire this as a unary server interceptor so every mutation gets dedup automatically — no per-handler boilerplate. Callers own retry identity; your service owns replay correctness. This mirrors the Stripe idempotency key contract applied directly to the gRPC metadata layer.$escape$,
  $escape$// proto: declare safety level per RPC
rpc GetUser(GetUserRequest) returns (User) {
  option idempotency_level = NO_SIDE_EFFECTS;
}
rpc UpdateUser(UpdateUserRequest) returns (User) {
  option idempotency_level = IDEMPOTENT;
}

// Go server: enforce idempotency key for unsafe mutations
func (s *Server) CreateOrder(ctx context.Context, req *pb.CreateOrderRequest) (*pb.Order, error) {
    md, _ := metadata.FromIncomingContext(ctx)
    keys := md.Get("idempotency-key")
    if len(keys) == 0 {
        return nil, status.Error(codes.InvalidArgument, "idempotency-key metadata required")
    }
    // check Redis cache: if hit, unmarshal and return cached *pb.Order
}$escape$,
  $escape$go$escape$,
