INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c67f1f8a-be43-4afe-8ba7-9c9ca2f07932',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC Caching — Why HTTP Headers Don't Apply and What to Do Instead$escape$,
  $escape$gRPC runs over HTTP/2 but bypasses standard HTTP caching semantics entirely. Cache-Control headers, ETags, and 304 responses have no meaning inside a gRPC channel — binary Protobuf frames are multiplexed streams, not cacheable HTTP resources. CDNs see opaque HTTP/2 frames and cannot cache gRPC traffic. The only CDN path is gRPC-Web, which serializes unary RPCs to HTTP/1.1-compatible framing, enabling edge caching for read-heavy endpoints.

For conditional request patterns, use gRPC metadata as a header substitute. Embed a version token (row version or content checksum) in response trailing metadata under x-etag. Clients echo it back via x-if-none-match on the next call. A server unary interceptor checks the incoming tag against the cached value — on a hit, it skips the handler entirely and returns the cached response with an x-cache: HIT flag. Note: gRPC has no 304 equivalent in its status code set, so the full response is still transmitted unless you model "not modified" as a dedicated proto response field. For real bandwidth savings, cache serialized Protobuf bytes in Redis and bypass handler execution on cache hits.$escape$,
  $escape$func CacheInterceptor(rdb *redis.Client) grpc.UnaryServerInterceptor {
    return func(ctx context.Context, req any, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (any, error) {
        md, _ := metadata.FromIncomingContext(ctx)
        clientETag := md.Get("x-if-none-match")

        cacheKey := fmt.Sprintf("rpc:%s", info.FullMethod)
        if hit, err := rdb.Get(ctx, cacheKey).Bytes(); err == nil {
            etag := fmt.Sprintf("%x", sha256.Sum256(hit))
            hdr := metadata.Pairs("x-etag", etag, "x-cache", "HIT")
            if len(clientETag) > 0 && clientETag[0] == etag {
                hdr.Set("x-not-modified", "true")
            }
            grpc.SetHeader(ctx, hdr)
            // unmarshal hit bytes into response proto and return
        }
        return handler(ctx, req)
    }
}$escape$,
  $escape$go$escape$,
