INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2aefcffa-1dff-45d4-b1f0-ace94f99a64e',
  '00000000-0000-0000-0000-000000000001',
  $escape$gRPC — When to Reach for It Over REST and GraphQL$escape$,
  $escape$gRPC wins when you control both ends of the wire. Its contract-first model via `.proto` files generates strongly-typed client and server stubs across languages — eliminating the drift that kills REST integrations. HTTP/2 multiplexing means a single connection handles concurrent streams without head-of-line blocking, critical for high-throughput internal services. Where REST requires polling and GraphQL subscriptions need WebSocket negotiation, gRPC gives you native bidirectional streaming via `ServerStreamingCall`, `ClientStreamingCall`, and `DuplexStreamingCall` out of the box.

Choose REST when exposing public APIs — browsers and third-party clients expect it. Choose GraphQL when clients have wildly different data-shape requirements and you want to avoid over-fetching. Choose gRPC when you're building synchronous service-to-service RPC in a polyglot microservices mesh, need sub-millisecond latency on binary payloads, or require streaming semantics. Protobuf's binary encoding is 3–10x smaller than JSON. Add interceptors for cross-cutting concerns (auth, tracing) and gRPC integrates cleanly with service meshes like Istio via its native HTTP/2 metadata headers.$escape$,
  $escape$// proto definition drives everything
syntax = "proto3";
service OrderService {
  rpc PlaceOrder (OrderRequest) returns (OrderResponse);
  rpc TrackOrder (TrackRequest) returns (stream TrackEvent); // server-streaming
}

// Generated Go client — strongly typed, no JSON marshaling
conn, _ := grpc.NewClient("orders:50051", grpc.WithTransportCredentials(insecure.NewCredentials()))
client := pb.NewOrderServiceClient(conn)

stream, _ := client.TrackOrder(ctx, &pb.TrackRequest{OrderId: "ord_123"})
for {
    event, err := stream.Recv() // blocks until next server push
    if err == io.EOF { break }
    log.Println(event.Status)
}$escape$,
  $escape$go$escape$,
